{
  "name": "智能文本风格迁移助手",
  "description": "一个利用 AI 将源文本内容转换为参考文本风格（格式、语气、排版）的工具。"
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// Using Gemini 3 Pro for complex reasoning and formatting tasks
export const GEMINI_MODEL_NAME = 'gemini-3-pro-preview';

export const INITIAL_SOURCE_PLACEHOLDER = `<p>在此处粘贴或输入您的<strong>源文本</strong>...</p><p>例如：这是一份普通的会议记录，包含了时间、地点和参与人员。</p>`;
export const INITIAL_STYLE_PLACEHOLDER = `<p>在此处输入<strong>参考风格</strong>...</p><p>例如：请使用商务正式的语气，将重点部分加粗，使用红色高亮关键数据，并使用序号列表列出项目。</p>`;

export interface StyleTransferRequest {
  sourceHtml: string;
  referenceText: string;
}

export interface ProcessingState {
  isLoading: boolean;
  error: string | null;
  isSuccess: boolean;
}

import { GoogleGenAI } from "@google/genai";
import { GEMINI_MODEL_NAME } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Sends the source HTML and reference style to Gemini to generate the transformed content.
 */
export const transformTextStyle = async (sourceHtml: string, referenceText: string): Promise<string> => {
  try {
    const prompt = `
      你是一个专业的文档排版与风格迁移专家。

      请根据以下两部分内容完成任务：

      1. **源文本 (Source Text)**：这是一段带有原始HTML格式的文本。
      2. **参考风格 (Reference Style)**：这是一段描述或示例文本，定义了目标风格、语气、颜色使用、粗体使用、列表格式等。

      **任务要求**：
      - 保持【源文本】的核心内容和语义不变。
      - 将【源文本】的格式、语气、视觉风格（如颜色、字体粗细、HTML标签结构）修改为符合【参考风格】的样子。
      - 如果参考风格包含特定的颜色（例如“红色高亮”），请使用内联 CSS (e.g., style="color: red")。
      - 输出结果必须是纯 HTML 代码片段（不要包含 \`\`\`html 标记，直接返回 HTML 内容），可以直接嵌入到 div 中显示。

      ---

      **源文本 (HTML)**:
      ${sourceHtml}

      **参考风格**:
      ${referenceText}

      **输出 (HTML Code Only)**:
    `;

    const response = await ai.models.generateContent({
      model: GEMINI_MODEL_NAME,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 2048 }, // Allow some thinking for complex formatting logic
      }
    });

    let result = response.text || "";

    // Cleanup: Remove markdown code blocks if the model accidentally included them
    result = result.replace(/^```html\s*/i, '').replace(/\s*```$/, '');

    return result;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "风格迁移失败，请检查 API Key 或网络连接。");
  }
};

import React, { useRef, useEffect, useState } from 'react';

interface RichInputProps {
  label: string;
  placeholderHtml: string;
  value: string;
  onChange: (html: string) => void;
  readOnly?: boolean;
  minHeight?: string;
  bgColor?: string;
}

export const RichInput: React.FC<RichInputProps> = ({ 
  label, 
  placeholderHtml, 
  value, 
  onChange, 
  readOnly = false,
  minHeight = "h-64",
  bgColor = "bg-white"
}) => {
  const contentEditableRef = useRef<HTMLDivElement>(null);
  const [isFocused, setIsFocused] = useState(false);

  // Sync external value changes to innerHTML, but only if not focused (to prevent cursor jumping)
  useEffect(() => {
    if (contentEditableRef.current && !isFocused && value !== contentEditableRef.current.innerHTML) {
      if (value === '') {
         contentEditableRef.current.innerHTML = placeholderHtml;
      } else {
         contentEditableRef.current.innerHTML = value;
      }
    }
    // Handle initial load specific case
    if (contentEditableRef.current && value === '' && !isFocused) {
        contentEditableRef.current.innerHTML = placeholderHtml;
    }
  }, [value, isFocused, placeholderHtml]);

  const handleInput = (e: React.FormEvent<HTMLDivElement>) => {
    if (contentEditableRef.current) {
      onChange(contentEditableRef.current.innerHTML);
    }
  };

  const handleFocus = () => {
    setIsFocused(true);
    // Clear placeholder logic if needed, but for rich text usually we just let user delete
    // Simple logic: if content matches placeholder exactly, clear it? 
    // For this app, we'll let the user decide what to delete to keep it simple and robust.
  };

  const handleBlur = () => {
    setIsFocused(false);
  };

  return (
    <div className="flex flex-col h-full">
      <div className="flex justify-between items-center mb-2">
        <label className="text-sm font-semibold text-gray-700 uppercase tracking-wider">
          {label}
        </label>
        {!readOnly && (
            <span className="text-xs text-gray-400 font-light">支持富文本粘贴</span>
        )}
      </div>
      <div 
        className={`
          flex-grow w-full rounded-xl border-2 transition-all duration-200 ease-in-out overflow-hidden
          ${isFocused ? 'border-blue-500 shadow-md ring-2 ring-blue-100' : 'border-gray-200 hover:border-gray-300'}
          ${bgColor}
        `}
      >
        <div
          ref={contentEditableRef}
          className={`
            w-full h-full p-4 outline-none overflow-y-auto text-gray-800 rich-editor-content
            ${minHeight} 
            ${readOnly ? 'cursor-default' : 'cursor-text'}
          `}
          contentEditable={!readOnly}
          onInput={handleInput}
          onFocus={handleFocus}
          onBlur={handleBlur}
          suppressContentEditableWarning={true}
        />
      </div>
    </div>
  );
};

import React from 'react';

interface ButtonProps {
  onClick: () => void;
  disabled?: boolean;
  children: React.ReactNode;
  variant?: 'primary' | 'secondary';
  className?: string;
}

export const Button: React.FC<ButtonProps> = ({ 
  onClick, 
  disabled = false, 
  children, 
  variant = 'primary',
  className = ''
}) => {
  const baseStyle = "px-6 py-3 rounded-lg font-medium transition-all duration-200 flex items-center justify-center space-x-2 shadow-sm active:scale-95";

  const variants = {
    primary: "bg-gradient-to-r from-blue-600 to-indigo-600 text-white hover:from-blue-700 hover:to-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed shadow-blue-500/30",
    secondary: "bg-white text-gray-700 border border-gray-300 hover:bg-gray-50 disabled:opacity-50"
  };

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`${baseStyle} ${variants[variant]} ${className}`}
    >
      {children}
    </button>
  );
};

import React, { useState, useCallback } from 'react';
import { RichInput } from './components/RichInput';
import { Button } from './components/Button';
import { transformTextStyle } from './services/geminiService';
import { INITIAL_SOURCE_PLACEHOLDER, INITIAL_STYLE_PLACEHOLDER } from './constants';
import { ProcessingState } from './types';

