const App: React.FC = () => {
  // State for inputs
  const [sourceContent, setSourceContent] = useState<string>(INITIAL_SOURCE_PLACEHOLDER);
  const [styleContent, setStyleContent] = useState<string>(INITIAL_STYLE_PLACEHOLDER);

  // State for output and processing
  const [outputContent, setOutputContent] = useState<string>('<p class="text-gray-400 italic">等待生成...</p>');
  const [status, setStatus] = useState<ProcessingState>({
    isLoading: false,
    error: null,
    isSuccess: false
  });

  const handleGenerate = useCallback(async () => {
    if (!sourceContent || !styleContent) {
      setStatus(prev => ({ ...prev, error: "请确保源文本和参考风格都不为空。" }));
      return;
    }

    setStatus({ isLoading: true, error: null, isSuccess: false });
    setOutputContent('<p class="text-gray-400 animate-pulse">AI 正在思考并重写您的文案...</p>');

    try {
      const result = await transformTextStyle(sourceContent, styleContent);
      setOutputContent(result);
      setStatus({ isLoading: false, error: null, isSuccess: true });
    } catch (err: any) {
      setStatus({ 
        isLoading: false, 
        error: err.message || "生成过程中发生了错误。", 
        isSuccess: false 
      });
      setOutputContent('<p class="text-red-500">生成失败，请重试。</p>');
    }
  }, [sourceContent, styleContent]);

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 pb-12">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-blue-600 p-2 rounded-lg">
               <MagicIcon />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-700 to-indigo-700">
              智能文本风格迁移助手
            </h1>
          </div>
          <div className="text-sm text-gray-500 hidden sm:block">
            Powered by Gemini 2.0 Pro
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Error Notification */}
        {status.error && (
          <div className="mb-6 p-4 rounded-lg bg-red-50 border border-red-200 text-red-700 flex items-center animate-fade-in">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            {status.error}
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Left Column: Inputs */}
          <div className="space-y-6 flex flex-col h-full">

            <div className="bg-white p-1 rounded-2xl shadow-sm border border-gray-200 flex-1 flex flex-col">
              <div className="p-5 flex-1">
                <RichInput 
                  label="1. 源文本 (支持富文本粘贴)" 
                  value={sourceContent}
                  onChange={setSourceContent}
                  placeholderHtml={INITIAL_SOURCE_PLACEHOLDER}
                  minHeight="h-48 lg:h-64"
                />
              </div>
            </div>

            <div className="bg-white p-1 rounded-2xl shadow-sm border border-gray-200 flex-1 flex flex-col">
              <div className="p-5 flex-1">
                <RichInput 
                  label="2. 参考风格 (定义格式与语气)" 
                  value={styleContent}
                  onChange={setStyleContent}
                  placeholderHtml={INITIAL_STYLE_PLACEHOLDER}
                  minHeight="h-32 lg:h-48"
                  bgColor="bg-gray-50"
                />
              </div>
            </div>

            <div className="pt-2">
              <Button 
                onClick={handleGenerate} 
                disabled={status.isLoading}
                className="w-full text-lg shadow-lg hover:shadow-xl transform transition hover:-translate-y-0.5"
              >
                {status.isLoading ? (
                  <>
                    <LoaderIcon />
                    正在优化中...
                  </>
                ) : (
                  <>
                    <MagicIcon />
                    <span>开始生成风格化文本</span>
                  </>
                )}
              </Button>
            </div>
          </div>

          {/* Right Column: Output */}
          <div className="flex flex-col h-full">
             <div className="bg-white rounded-2xl shadow-lg border border-gray-200 flex-grow flex flex-col overflow-hidden ring-1 ring-gray-900/5">
                <div className="bg-gray-50 border-b border-gray-200 px-6 py-4 flex justify-between items-center">
                  <h2 className="text-lg font-bold text-gray-800 flex items-center">
                    <span className="w-2 h-6 bg-indigo-500 rounded-full mr-3"></span>
                    3. 优化结果
                  </h2>
                  {status.isSuccess && (
                    <span className="text-xs font-semibold text-green-600 bg-green-100 px-2 py-1 rounded-full">
                      生成成功
                    </span>
                  )}
                </div>
                <div className="flex-grow p-6 relative bg-white">
                  <div className="absolute inset-0 p-6 overflow-y-auto">
                    <div 
                      className="prose prose-blue max-w-none rich-editor-content"
                      dangerouslySetInnerHTML={{ __html: outputContent }}
                    />
                  </div>
                </div>
             </div>
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { GEMINI_MODEL_NAME } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Sends the source HTML and reference style to Gemini to generate the transformed content.
 */
export const transformTextStyle = async (sourceHtml: string, referenceText: string): Promise<string> => {
  try {
    const prompt = `
      你是一个专业的文档重写与风格迁移专家。你的核心任务是：将【源文本】重写，使其在语气、格式、排版结构和视觉样式上**完美复刻**【参考风格】。

      **输入内容：**
      1. **源文本 (Source)**: ${sourceHtml}
      2. **参考风格 (Reference)**: ${referenceText}

      **严格执行以下指令 (Critical Instructions)**:

      1. **内容重构 (增删改)**：
         - **授权**：为了匹配目标风格，你必须对源文本进行**增、删、改**。
         - **语气**：严格模仿参考文本的语气（如：严肃商务、幽默活泼、紧迫感营销、学术严谨等）。如果参考风格喜欢用短句，就将源文本拆分为短句；如果喜欢用排比，就改写为排比。
         - **结构**：模仿参考文本的段落结构。

      2. **视觉复刻 (颜色与字体)**：
         - **颜色**：如果参考风格中体现了特定颜色（如“重点用红色”、“标题用蓝色”），或者参考文本本身包含颜色，**必须**使用内联 CSS (例如 \`style="color: #e11d48; font-weight: bold"\`) 来实现。
         - **格式**：严格还原粗体、斜体、下划线、字号大小的变化。

      3. **排版格式**：
         - 严格遵循换行习惯（如：是否空行、列表间距）。
         - 还原列表样式（序号、圆点、emoji 列表头）。

      **输出要求**：
      - 仅输出最终的 **HTML 代码**。
      - 不要包含 \`\`\`html 或 markdown 标记。
      - 输出的代码将直接嵌入到 div 中。

      请开始生成的 HTML 代码：
    `;

    const response = await ai.models.generateContent({
      model: GEMINI_MODEL_NAME,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 2048 }, 
      }
    });

    let result = response.text || "";

    // Cleanup: Remove markdown code blocks if the model accidentally included them
    result = result.replace(/^```html\s*/i, '').replace(/\s*```$/, '');

    return result;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "风格迁移失败，请检查 API Key 或网络连接。");
  }
};

import React, { useState, useCallback, useRef } from 'react';
import { RichInput } from './components/RichInput';
import { Button } from './components/Button';
