const App: React.FC = () => {
  // State for inputs
  const [sourceContent, setSourceContent] = useState<string>(INITIAL_SOURCE_PLACEHOLDER);
  const [styleContent, setStyleContent] = useState<string>(INITIAL_STYLE_PLACEHOLDER);

  // State for output and processing
  const [outputContent, setOutputContent] = useState<string>('<p class="text-gray-400 italic">等待生成...</p>');
  const [status, setStatus] = useState<ProcessingState>({
    isLoading: false,
    error: null,
    isSuccess: false
  });

  const [isCopied, setIsCopied] = useState(false);
  const outputRef = useRef<HTMLDivElement>(null);

  const handleGenerate = useCallback(async () => {
    if (!sourceContent || !styleContent) {
      setStatus(prev => ({ ...prev, error: "请确保源文本和参考风格都不为空。" }));
      return;
    }

    setStatus({ isLoading: true, error: null, isSuccess: false });
    setIsCopied(false);
    setOutputContent('<p class="text-gray-400 animate-pulse">AI 正在思考并重写您的文案...</p>');

    try {
      const result = await transformTextStyle(sourceContent, styleContent);
      setOutputContent(result);
      setStatus({ isLoading: false, error: null, isSuccess: true });
    } catch (err: any) {
      setStatus({ 
        isLoading: false, 
        error: err.message || "生成过程中发生了错误。", 
        isSuccess: false 
      });
      setOutputContent('<p class="text-red-500">生成失败，请重试。</p>');
    }
  }, [sourceContent, styleContent]);

  const handleCopy = useCallback(async () => {
    if (!outputContent || !status.isSuccess) return;

    try {
      // Create HTML blob for rich text paste
      const htmlBlob = new Blob([outputContent], { type: 'text/html' });
      // Create text blob for plain text paste (getting innerText from ref ensures clean newlines)
      const textBlob = new Blob([outputRef.current?.innerText || ""], { type: 'text/plain' });

      const data = [new ClipboardItem({ 
        "text/html": htmlBlob, 
        "text/plain": textBlob 
      })];

      await navigator.clipboard.write(data);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    } catch (err) {
      console.error("Copy failed", err);
      // Simple fallback
      try {
         await navigator.clipboard.writeText(outputRef.current?.innerText || "");
         setIsCopied(true);
         setTimeout(() => setIsCopied(false), 2000);
      } catch (fallbackErr) {
         setStatus(prev => ({ ...prev, error: "复制失败，请手动复制。" }));
      }
