import { GoogleGenAI } from "@google/genai";
import { GEMINI_MODEL_NAME } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Sends the source HTML and reference style to Gemini to generate the transformed content.
 */
export const transformTextStyle = async (sourceHtml: string, referenceText: string): Promise<string> => {
  try {
    const prompt = `
      你现在的身份是一名顶级的**代笔作家 (Ghostwriter)** 和 **语言风格模仿专家**。
      你的任务不是简单的修改格式，而是要**完全成为【参考风格】的作者**，用他/她的口吻、语境、思维方式和语言习惯，重新撰写【源文本】。

      **输入内容：**
      1. **源文本 (需改写的内容)**: 
      ${sourceHtml}

      2. **参考风格 (模仿对象)**: 
      ${referenceText}

      **核心指令 (必须严格遵守)**:

      1. **深度人格模仿 (Persona & Tone)**:
         - **完全代入**：仔细分析【参考风格】的作者是谁（例如：是严肃的老板、活泼的运营、体贴的客服，还是严谨的工程师？）。你现在就是这个人。
         - **像真人一样说话**：拒绝 AI 翻译腔或机械感。如果参考文本使用了口语、俚语、特定的感叹词（如“哎呀”、“亲们”）、或者特定的行文节奏（短促有力 vs 娓娓道来），你必须完美复刻。
         - **语境对齐**：如果参考文本是在发朋友圈、写周报、还是写正式公文，你的输出必须让人感觉是在**完全相同的场景**下写出来的。

      2. **内容重构 (Rewriting)**:
         - **大胆增删改**：不要拘泥于源文本的字面措辞。为了符合参考风格的语气，你可以大幅度调整句式、增加连接词、甚至添加符合该人设的口头禅或语气助词。
         - **保留核心信息**：源文本里的关键事实（数据、时间、地点、核心观点）不能丢，但怎么说这些事实，完全由【参考风格】决定。

      3. **视觉与排版复刻 (Visual Style)**:
         - **格式即性格**：如果参考文本喜欢用**粗体**强调重点，或者用红色标出警告，或者喜欢用 Emoji 列表，你必须一模一样地照做。
         - **内联样式**：涉及颜色或特殊排版时，必须使用 HTML 内联样式 (e.g., \`style="color: #d97706; font-weight: bold"\`)。
         - **排版结构**：完全照搬参考文本的换行习惯（空行多 vs 紧凑）、列表符号样式（1. vs - vs Emoji）。

      **输出要求**:
      - 输出结果必须是 **纯 HTML 代码**。
      - 不要包含任何解释性文字，不要包含 \`\`\`html 标记。
      - 最终结果将直接展示给用户，必须具备极高的可读性和感染力。

      请开始生成：
    `;

    const response = await ai.models.generateContent({
      model: GEMINI_MODEL_NAME,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 2048 }, 
      }
    });

    let result = response.text || "";

    // Cleanup: Remove markdown code blocks if the model accidentally included them
    result = result.replace(/^```html\s*/i, '').replace(/\s*```$/, '');

    return result;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "风格迁移失败，请检查 API Key 或网络连接。");
  }
};

