    if (!outputContent || !status.isSuccess) return;

    try {
      const fullHtml = `
        <!DOCTYPE html>
        <html>
        <head>
          <meta charset="utf-8">
          <style>
            body { font-family: 'Noto Sans SC', sans-serif; color: #1f2937; line-height: 1.6; }
