/**
 * 将源文本内容转换为参考文本的视觉风格和语言语气。
 */
export const transformTextStyle = async (sourceHtml: string, referenceHtml: string): Promise<string> => {
  // Always initialize a new GoogleGenAI instance inside the function to ensure the correct API key is used.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const prompt = `
      你是一位精通“视觉克隆”与“人格拟合”的顶级文案专家和前端工程师。
      任务：提取【参考文档】的**所有视觉细节**和**说话语气**，并将其完美应用到【源文本】的内容上。

      **输入数据：**
      1. **源文本 (核心内容，需保留原意 and 长度)**: 
      ${sourceHtml}

      2. **参考文档 (样式、色号、语气模版)**: 
      ${referenceHtml}

      **执行核心指令：**

      1. **视觉基因提取 (Visual Cloning - 核心重点)**:
         - **精准色号**：分析参考文档中的 HTML 内联样式。如果其中使用了特定的颜色（例如 \`color: #e11d48\` 或 \`color: rgb(...)\`），你必须在输出中对相应的关键词、重点短语使用**完全相同**的内联样式。
         - **格式复刻**：观察参考文档如何使用 **加粗 (strong/b)**、*斜体 (em/i)*、下划线。将其排版风格应用到源文本的重点部分。
         - **排版对齐**：复刻参考文档的换行频率、缩进方式以及列表符号（如使用特定 Emoji 作为列表头）。

      2. **真人语气模拟 (Human Tone)**:
         - **口吻拟合**：分析参考文档是冷冰冰的 AI，还是一个真实的、有情感的人？复刻其语境下的措辞习惯（例如：亲切感、专业感、幽默感）。
         - **细节复刻**：如果参考文档喜欢用“~”结尾，或者喜欢用某些特定的语气助词，请在不改变源文本原意的情况下，将其融入。

      3. **长度与内容克制 (Strict Constraint)**:
         - **严禁扩写或缩写**：生成的文本长度必须与【源文本】基本保持一致。
         - **信息保真**：源文本的所有核心事实、数据、逻辑点必须完整保留。

      **输出规范**:
      - 必须返回 **纯 HTML 代码**。
      - 所有的视觉样式（颜色、加粗等）必须直接写在标签的 \`style\` 属性中。
      - 严禁包含 \`\`\`html 这种 Markdown 标记，直接输出 HTML 内容。
      - 严禁包含 any 前言、后记或解释性文字。

      请开始克隆：
    `;

    // Using gemini-3-pro-preview for high-quality complex reasoning
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL_NAME,
      contents: prompt,
      config: {
        // Utilizing thinking budget for better reasoning depth in style transfer
        thinkingConfig: { thinkingBudget: 2048 }, 
      }
    });

    // Access the text property directly from the response object
    let result = response.text || "";

    // 清理可能误生成的 Markdown 标签
    result = result.replace(/^```html\s*/i, '').replace(/\s*```$/, '');

    return result;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "风格迁移失败，请检查 API Key 或网络连接。");
  }
};

import React, { useState, useCallback, useRef } from 'react';
import { RichInput } from './components/RichInput';
import { Button } from './components/Button';
import { transformTextStyle } from './services/geminiService';
import { INITIAL_SOURCE_PLACEHOLDER, INITIAL_STYLE_PLACEHOLDER } from './constants';
import { ProcessingState } from './types';

// Icons
